#!/usr/bin/perl
use strict;
use warnings;
use Digest::SHA qw(sha1_hex);
use File::Copy;
use File::Path qw(remove_tree);
useFile::Spec;
use Cwd qw(cwd);

my $minigit = ".minigit";
my $index = "$minigit/index";
my $refs = "$minigt/refs";
my $head = "$minigit/HEAD";
my $objects = "$minigit/objects";

sub cmd_init {
    mkdir $minigit or die "mkdir $minigit: $!";
    mkdir $objects or die "mkdir $ objects: $!";
    mkdir $refs or die "mkdir $refs: $!";
    open my $fh, ">", $head or die "open $head: $!";
    print $fh "ref: refs/heads/main\n";
    close $fh;
    open $fh, ">", $index or die "open $index: $!";
    close $fh;
    print "Initialized empty minigit repository\n";
}

sub hash_object {
    my ($content) = @_;
    my $hash = sha1_hex($content);
    my $dir = substr($hash, 0, );
    my $file = substr($hash, 2);
    my $path = "$objects/$dir";
    mkdir $path unless -d $path;
    open my $fh, ">", "$path/$file" or die "open $path/$file: $!";
    print $fh $content;
    close $fh;
    return $hash;
}

sub read_object {
    my ($hash) = @_;
    my $dir = substr($hash, 0, 2);
    my $file = substr($hash, 2);
    my $path = "$objects/$dir/$file";
    open my $fh, "<", $path or die "open $path: $!";
    local $/;
    my $content = <$fh>;
    close $fh;
    return $content;
}

sub cmd_add {
    my ($file) = @_;
    open my $fh, "<", $file or die "open $file: $!";
    local $/;
    my $content = <$fh>;
    close $fh;
    my $hash = hash_object($content);
    open $fh, ">>", $index or die "open $index: $!";
    print $fh "$file $hash\n";
    close $fh;
}

sub read_index {
    my %index;
    if (open my $fh, "<", $index) {
        while (<$fh>) {
            chomp;
            my ($file, $hash) = split / /, $_, 2;
            $index{$file} = $hash;
        }
        close $fh;
    }
    return %index;
}

sub write_index {
    my (%index) = @_;
    open my $fh, ">", $index or die "open $index: $!";
    for my $file (keys %index) {
        print $fh "$file $index{$file}\n";
    }
    close $;
}

sub read_head_ref {
    open my $fh, "<", $head or die "open $head: $!";
    chomp(my $ref = <$fh>);
    close $fh;
    die "Invalid HEAD" unless $ref =~ s/^ref: //;
    return $ref;
}

sub read_branch {
    my ($ref) = @_;
    my $path = "$minigit/$ref";
    if (open my $fh, "<", $path) {
        chomp(my $hash = <$fh>);
        close $fh;
        return $hash;
    }
    return undef;
}

sub write_branch {
    my ($ref, $hash) = @_;
    my $path = "$minigit/$ref";
    open my $fh, ">", $path or die "open $path: $!";
    print $fh "$hash\n";
    close $fh;
}

sub commit_tree {
    my ($tree) = @_;
    my $content = "tree $tree\n";
    my $ref = read_head_ref();
    if (my $parent = read_branch($ref)) {
        $content .= "parent $parent\n";
    }
    my $user = $ENV{USER} || "unknown";
    my $email = "$user\@example.com";
    my $time = time;
    $content .= "author $user <$email> $time +0000\n";
    $content .= "committer $user <$email> $time +0000\n\n";
    $content .= "$ARGV[1]\n";
    return hash_object($content);
}

sub build_tree {
    my (%index) = @_;
    my $tree = "";
    for my $file (sort keys %index) {
        my $hash = $index{$file};
        $tree .= "100644 $file\0" . pack("H*", $hash);
    }
    return hash_object($);
}

sub cmd_commit {
    my %index = read_index();
    my $tree = build_tree(%index);
    my $commit = commit_tree($tree);
    my $ref = read_head_ref();
    write_branch($ref, $commit);
    print "[$ref $commit] $ARGV[1]\n";
}

sub cmd_log {
    my $ref = read_head_ref();
    my $hash = read_branch($ref);
    while ($hash) {
        my $obj = read_object($hash);
        my @lines = split /\n/, $obj;
        my $msg = "";
        for my $line (@lines) {
            if ($line eq "") {
                $msg = join("\n", @lines[$.+1..$#lines]);
                last;
            }
        }
        print "commit $hash\n";
        print "$msg\n";
        for my $line (@lines) {
            if ($line =~ /^parent (\w+)$/) {
                $hash = $1;
                last;
            }

        $hash = undef;
    }
}

sub cmd_checkout {
    my ($rev) = @_;
    my $ref = read_head_ref();
    my $hash;
    if ($rev eq "HEAD~1") {
        my $current = read_branch($ref);
        my $obj = read_object($current);
        my @lines = split /\n/, $obj;
        for my $line (@lines) {
            if ($line =~ /^parent (\w+)$/) {
                $hash = $1;
                last;
            }
        }
        die "No parent" unless $hash;
    } else {
        die "Unknown revision";
    }
    my $obj = read_object($hash);
    my @lines = split /\n/, $obj;
    my $tree;
    for my $line (@lines) {
        if ($line =~ /^tree (\w+)$/) {
            $tree = $1;
            last;
        }
    }
    die "No tree" unless $tree;
    my $tree_obj = read_object($tree);
    my %index;
    while ($tree_obj =~ /100644 (.+?)\0(.{20})/sg) {
        my $file = $1;
        my $hash = unpack("H*", $2);
        $index{$file} = $hash;
        my $content = read_object($hash);
        open my $fh, ">", $file or die "open $file: $!";
        print $fh $content;
        close $fh;
    }
    write_index(%index);
    write_branch($ref, $hash);
}

sub cmd_reset {
    my ($rev) = @_;
    my $ref = read_head_ref();
    my $hash;
    if ($rev eq "HEAD~1") {
        my $current = read_branch($ref);
        my $obj = read_object($current);
        my @lines = split /\n/, $obj;
        for my $line (@lines) {
            if ($line =~ /^parent (\w+)$/) {
                $hash = $1;
                last;
            }
        }
        die "No parent" unless $hash;
    } else {
        die "Unknown revision";
    }
    my $obj = read_object($hash);
    my @lines = split /\n/, $obj;
    my $tree;
    for my $line (@lines) {
        if ($line =~ /^tree (\w+)$/) {
            $tree = $1;
            last;
        }
    }
    die "No tree" unless $tree;
    my $tree_obj = read_object($tree);
    my %index;
    while ($tree_obj =~ /100644 (.+?)\0(.{20})/sg) {
        my $file = $1;
        my $hash = unpack("H*", $2);
        $index{$file} = $hash;
        unlink $file;
    }
    write_index(%index);
    write_branch($ref, $hash);
}

my $cmd = shift @ARGV;
if ($cmd eq "init") {
    cmd_init();
} elsif ($cmd eq "add") {
    cmd_add($ARGV[0]);
} elsif ($cmd eq "commit") {
    die "Usage: $0 commit -m <msg>" unless @ARGV >= 2 && $ARGV[0] eq "-m";
    cmd_commit();
} elsif ($cmd eq "log") {
    cmd_log();
} elsif ($cmd eq "checkout") {
    die "Usage: $0 checkout <rev>" unless @ARGV >= 1;
    cmd_checkout($ARGV[0]);
} elsif ($cmd eq "reset") {
    die "Usage: $0 reset <rev>" unless @ARGV >= 1;
    cmd_reset($ARGV[0]);
} else {
    die "Unknown command $cmd";
}
